import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

function randomSeries() {
  var d = []
  for (var i = 0; i < 7; i++) d.push(Math.round(10 + Math.random() * 90))
  return d
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Value', data: [34, 55, 41, 67, 22, 48, 60] }],
    options: {
      chart: {
        height: 380,
        type: 'bar',
        id: 'rewind-demo',
        animations: { enabled: true },
        toolbar: { show: false },
        history: {
          enabled: true,
          maxDepth: 50,
          coalesceMs: 250,
          keyboard: true,
        },
        zoom: { enabled: true },
      },
      colors: ['#7c5cf6'],
      plotOptions: { bar: { columnWidth: '55%', borderRadius: 4 } },
      dataLabels: { enabled: false },
      title: {
        text: 'Undo / redo over data, zoom, and selection',
        align: 'left',
      },
      xaxis: { categories: ['A', 'B', 'C', 'D', 'E', 'F', 'G'] },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id, then wire the same buttons the vanilla build does.
    // (randomSeries lives in the shared head script.) History drives the chart
    // instance directly, so no React state changes and the chart is never
    // re-rendered under it.
    let chart
    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('rewind-demo')
      if (!chart) return
      window.clearInterval(timer)

      const undoBtn = document.getElementById('undo')
      const redoBtn = document.getElementById('redo')
      const readout = document.getElementById('readout')

      function syncButtons(state) {
        if (!state) state = chart.history.state()
        undoBtn.disabled = !state.canUndo
        redoBtn.disabled = !state.canRedo
        readout.innerHTML =
          'history: <b>' +
          (state.index + 1) +
          ' / ' +
          state.length +
          '</b> checkpoints'
      }

      chart.addEventListener('historyChange', function (c, state) {
        syncButtons(state && state.length != null ? state : undefined)
      })

      undoBtn.addEventListener('click', function () {
        chart.history.undo()
      })
      redoBtn.addEventListener('click', function () {
        chart.history.redo()
      })
      document
        .getElementById('randomize')
        .addEventListener('click', function () {
          chart.updateSeries([{ name: 'Value', data: randomSeries() }])
        })
      document.getElementById('reset').addEventListener('click', function () {
        chart.history.clear()
      })

      // initial state once the baseline checkpoint lands
      window.setTimeout(syncButtons, 300)
    }, 50)

    return () => {
      window.clearInterval(timer)
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <button id="undo" className="primary" disabled>
            Undo
          </button>
          <button id="redo" className="primary" disabled>
            Redo
          </button>
          <button id="randomize">Randomize data</button>
          <button id="reset">Clear history</button>
          <span className="readout" id="readout">
            history: empty
          </span>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="bar"
          height={380}
        />
      </div>

      <div className="panel">
        <div className="note">
          History is enabled with{' '}
          <code>chart: &#123; history: &#123; enabled: true &#125; &#125;</code>
          . Every data update, zoom, and point selection commits a checkpoint.
          Press Randomize a few times, then step back with Undo / Redo (or press
          <code>Cmd/Ctrl + Z</code> and <code>Shift + Cmd/Ctrl + Z</code>).
          Toggling a series in the legend and zooming also create checkpoints.
          The buttons enable from the <code>historyChange</code> event via{' '}
          <code>chart.history.state()</code>.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

